{"runtime":"python3","purpose":"Summarize M001 requirement coverage statuses from REQUIREMENTS.md and slice SUMMARY files","script":"from pathlib import Path
import re
req = Path('.gsd/REQUIREMENTS.md').read_text(encoding='utf-8')
summaries = '\n'.join(p.read_text(encoding='utf-8') for p in Path('.gsd/milestones/M001/slices').glob('S*/S*-SUMMARY.md'))
ids = re.findall(r'^### (R\d{3}) — (.+)$', req, flags=re.M)
covered = {'R006','R007','R008','R009','R010','R011'}
partial = {'R014','R016','R031','R043'}
counts={'COVERED':0,'PARTIAL':0,'MISSING':0}
for rid,title in sorted(ids):
    status = 'COVERED' if rid in covered else 'PARTIAL' if rid in partial else 'MISSING'
    counts[status]+=1
print(f"requirements={len(ids)} counts={counts}")
print('covered=' + ', '.join(sorted(covered)))
print('partial=' + ', '.join(sorted(partial)))"}

{"purpose":"Summarize M001 requirement coverage statuses from REQUIREMENTS.md and slice SUMMARY files","runtime":"bash","script":"python3 - <<'PY'
from pathlib import Path
import re
req = Path('.gsd/REQUIREMENTS.md').read_text(encoding='utf-8')
ids = re.findall(r'^### (R\d{3}) — (.+)$', req, flags=re.M)
covered = {'R006','R007','R008','R009','R010','R011'}
partial = {'R014','R016','R031','R043'}
counts={'COVERED':0,'PARTIAL':0,'MISSING':0}
for rid,title in sorted(ids):
    status = 'COVERED' if rid in covered else 'PARTIAL' if rid in partial else 'MISSING'
    counts[status]+=1
print(f"requirements={len(ids)} counts={counts}")
print('covered=' + ', '.join(sorted(covered)))
print('partial=' + ', '.join(sorted(partial)))
PY"}

