from pathlib import Path
import re
root=Path('.gsd/milestones/M001/slices')
sections = ['Summary','Verification','Operational Readiness','Requirements Advanced','Requirements Validated','Known Limitations','Follow-ups','Not Proven By This UAT','UAT Type','UAT Steps','Expected Results','Acceptance Criteria','Integration Closure','What changed']

def extract(path):
    text=path.read_text(encoding='utf-8', errors='replace')
    lines=text.splitlines()
    title=lines[0] if lines else ''
    out=[f'## {path.relative_to(root)}', title]
    # yaml/frontmatter one-liners and bullets with key clues
    for pat in ['one_liner:', 'verification_result:', 'verification:']:
        for line in lines[:80]:
            if line.lower().startswith(pat):
                out.append(line)
    # Extract selected sections up to next h2/h1, capped
    for sec in sections:
        m=re.search(rf'(?im)^##+\s+{re.escape(sec)}\s*$', text)
        if not m: continue
        rest=text[m.end():]
        n=re.search(r'(?m)^##+\s+', rest)
        body=rest[:n.start()] if n else rest
        body_lines=[l.rstrip() for l in body.strip().splitlines() if l.strip()]
        if body_lines:
            out.append(f'### {sec}')
            out.extend(body_lines[:18])
            if len(body_lines)>18:
                out.append(f'... {len(body_lines)-18} more lines')
    return '\n'.join(out)

paths=[]
for p in sorted(root.glob('S*/S*-SUMMARY.md')):
    paths.append(p)
    uat=p.with_name(p.name.replace('-SUMMARY.md','-UAT.md'))
    if uat.exists(): paths.append(uat)
for chunk in [extract(p) for p in paths]:
    print(chunk)
    print('\n---\n')

